// Verificar si ya hay un proceso global activo
const procesoGlobalActivo = global.get('anvizProcesoGlobalActivo') || false;
const inicioProceso = global.get('anvizInicioProceso') || 0;

// Timeout de seguridad: si lleva más de 30 minutos, forzar reset
const MAX_DURACION_MS = 30 * 60 * 1000; // 30 minutos
const tiempoTranscurrido = Date.now() - inicioProceso;

if (procesoGlobalActivo && tiempoTranscurrido < MAX_DURACION_MS) {
    node.warn(`⏳ Proceso ya activo desde hace ${(tiempoTranscurrido/1000).toFixed(0)}s - IGNORANDO nueva ejecución`);
    node.status({ fill: 'yellow', shape: 'ring', text: 'Bloqueado - proceso activo' });
    return null;
}

if (procesoGlobalActivo && tiempoTranscurrido >= MAX_DURACION_MS) {
    node.warn(`⚠ Proceso colgado por más de 30min - FORZANDO RESET`);
}

// Marcar proceso como activo
global.set('anvizProcesoGlobalActivo', true);
global.set('anvizInicioProceso', Date.now());

node.status({ fill: 'green', shape: 'dot', text: 'Iniciando proceso' });
node.log('🔓 Bloqueo adquirido - iniciando proceso');

return msg;

// Lista de relojes a procesar
const relojes = [
    { ip: '192.168.7.243', sucursal: 'SAS' },
    { ip: '192.168.7.244', sucursal: 'SAS' },
    { ip: '192.168.7.245', sucursal: 'SAS' },
    { ip: '192.168.7.246', sucursal: 'SAS' },
    { ip: '192.168.7.247', sucursal: 'SAS' }
];

// Configuración de fechas: últimos 7 días
const diasAtras = 7;
const fechaHasta = new Date();
const fechaDesde = new Date();
fechaDesde.setDate(fechaDesde.getDate() - diasAtras);

const fechaDesdeStr = `${fechaDesde.getFullYear()}-${String(fechaDesde.getMonth()+1).padStart(2,'0')}-${String(fechaDesde.getDate()).padStart(2,'0')}`;
const fechaHastaStr = `${fechaHasta.getFullYear()}-${String(fechaHasta.getMonth()+1).padStart(2,'0')}-${String(fechaHasta.getDate()).padStart(2,'0')}`;

flow.set('fechaDesde', fechaDesdeStr);
flow.set('fechaHasta', fechaHastaStr);
flow.set('diasConsulta', diasAtras);

// Inicializar control de proceso
flow.set('relojes', relojes);
flow.set('relojActualIndex', 0);
flow.set('pausaEntreConsultas', 800);
flow.set('pausaEntreRelojes', 2000);

// Estadísticas globales por reloj
const estadoRelojes = relojes.map(r => ({
    ip: r.ip,
    sucursal: r.sucursal,
    estado: 'PENDIENTE',
    procesados: 0,
    insertados: 0,
    intentos: 0,
    error: null,
    duracion: 0
}));
flow.set('estadoRelojes', estadoRelojes);

// Lista de relojes para reintento (segunda pasada)
flow.set('relojesParaReintento', []);
flow.set('faseReintento', false);

// Estadísticas globales
flow.set('estadisticasGlobales', {
    totalProcesados: 0,
    totalInsertados: 0,
    inicioProceso: Date.now()
});

node.log('========================================');
node.log('🚀 INICIANDO PROCESO PARA TODOS LOS RELOJES');
node.log(`📋 Relojes a procesar: ${relojes.length}`);
node.log(`📅 Consultando últimos ${diasAtras} días (${fechaDesdeStr} al ${fechaHastaStr})`);
node.log('========================================');

msg.payload = 'start';
return msg;

const relojes = flow.get('relojes') || [];
const relojIndex = flow.get('relojActualIndex') || 0;
const faseReintento = flow.get('faseReintento') || false;

// Verificar si terminamos todos los relojes
if (relojIndex >= relojes.length) {
    const relojesParaReintento = flow.get('relojesParaReintento') || [];

    // Si no estamos en fase de reintento y hay relojes fallidos -> iniciar reintento
    if (!faseReintento && relojesParaReintento.length > 0) {
        node.log('========================================');
        node.log(`🔁 INICIANDO FASE DE REINTENTO`);
        node.log(`📋 Relojes a reintentar: ${relojesParaReintento.length}`);
        node.log('========================================');

        // Cambiar a fase de reintento
        flow.set('faseReintento', true);
        flow.set('relojes', relojesParaReintento);
        flow.set('relojActualIndex', 0);
        flow.set('relojesParaReintento', []);

        // Reiniciar el proceso con los relojes fallidos
        setTimeout(() => {
            node.send({ payload: 'reintento_inicio' });
        }, 3000);

        return null;
    }

    // Proceso completado - mostrar resumen y liberar bloqueo
    return [null, { payload: 'resumen_final' }];
}

// Obtener el reloj actual
const reloj = relojes[relojIndex];

node.log('========================================');
node.log(`🕒 ${faseReintento ? '[REINTENTO] ' : ''}PROCESANDO RELOJ ${relojIndex + 1}/${relojes.length}: ${reloj.ip} - ${reloj.sucursal}`);
node.log('========================================');

// Configurar el reloj actual
flow.set('relojActual', reloj);
flow.set('inicioRelojActual', Date.now());

// Resetear contadores para este reloj
flow.set('registroIndex', 0);
flow.set('batchIndex', 0);
flow.set('totalProcesados', 0);
flow.set('totalInsertados', 0);
flow.set('esUltimoBatch', false);
flow.set('todosLosRegistros', []);

// Actualizar estado del reloj
const estadoRelojes = flow.get('estadoRelojes') || [];
const estadoReloj = estadoRelojes.find(r => r.ip === reloj.ip);
if (estadoReloj) {
    estadoReloj.estado = 'PROCESANDO';
    estadoReloj.intentos += 1;
    flow.set('estadoRelojes', estadoRelojes);
}

msg.payload = 'start';
msg.reloj = reloj;
msg.relojIndex = relojIndex;
msg.readerIp = reloj.ip;
msg.sucursal = reloj.sucursal;

return [msg, null];

const reloj = flow.get('relojActual');
if (!reloj) {
    node.error('❌ No hay reloj actual configurado');
    return null;
}

const ip = reloj.ip;
const userid = 'admin';
const password = '12345';
const sucursal = reloj.sucursal;

flow.set('readerIp', ip);
flow.set('sucursal', sucursal);

msg.readerIp = ip;
msg.sucursal = sucursal;

msg.url = `http://${ip}/goform/chklogin?_t=${Date.now()}`;
msg.method = 'POST';
msg.headers = {
    'Content-Type': 'application/json',
    'Accept': 'application/json, text/plain, */*',
    'Referer': `http://${ip}/index.html`
};
msg.payload = {
    userid: userid,
    password: password
};

return msg;

function parseAnvizJSON(text) {
    if (typeof text !== 'string') return text;
    text = text.trim();

    try {
        return JSON.parse(text);
    } catch(e) {}

    let cleaned = text.replace(/,\s*}/g, '}');
    cleaned = cleaned.replace(/,\s*]/g, ']');
    cleaned = cleaned.replace(/([{,]\s*)([a-zA-Z_][a-zA-Z0-9_]*)\s*:/g, '$1"$2":');
    cleaned = cleaned.replace(/'/g, '"');
    cleaned = cleaned.replace(/[\x00-\x1F\x7F-\x9F]/g, '');

    try {
        return JSON.parse(cleaned);
    } catch(e) {
        const jsonMatch = cleaned.match(/\{[\s\S]*\}/);
        if (jsonMatch) {
            try {
                return JSON.parse(jsonMatch[0]);
            } catch(e2) {}
        }
        throw new Error(`No se pudo parsear JSON: ${e.message}`);
    }
}

// Función para marcar reloj como fallido y pasar al siguiente
function marcarFalloYContinuar(errorMsg) {
    const readerIp = flow.get('readerIp');
    const faseReintento = flow.get('faseReintento') || false;
    const estadoRelojes = flow.get('estadoRelojes') || [];
    const estadoReloj = estadoRelojes.find(r => r.ip === readerIp);

    if (estadoReloj) {
        estadoReloj.estado = faseReintento ? 'FALLIDO_DEFINITIVO' : 'FALLIDO_PRIMERA';
        estadoReloj.error = errorMsg;
        estadoReloj.duracion = Math.round((Date.now() - flow.get('inicioRelojActual')) / 1000);
        flow.set('estadoRelojes', estadoRelojes);
    }

    // Si NO es fase de reintento, agregar a lista de reintento
    if (!faseReintento) {
        const relojesParaReintento = flow.get('relojesParaReintento') || [];
        const relojActual = flow.get('relojActual');
        if (relojActual && !relojesParaReintento.find(r => r.ip === relojActual.ip)) {
            relojesParaReintento.push(relojActual);
            flow.set('relojesParaReintento', relojesParaReintento);
        }
    }

    // Pasar al siguiente reloj
    const relojActualIndex = flow.get('relojActualIndex') || 0;
    flow.set('relojActualIndex', relojActualIndex + 1);

    setTimeout(() => {
        node.send([null, { payload: 'siguiente_reloj' }]);
    }, 2000);
}

try {
    let data = msg.payload;

    if (typeof data === 'string') {
        data = parseAnvizJSON(data);
    }

    if (data.code === 'error' || data.code === 'Error') {
        throw new Error(`Login falló: ${data.msg || data.message || 'error desconocido'}`);
    }

    if (data.retvalue !== undefined && data.retvalue !== 0) {
        throw new Error(`Login retvalue: ${data.retvalue} - ${data.msg || ''}`);
    }

    const token = data.token || data.Token || data.TOKEN || (data.data && data.data.token);

    if (!token) {
        throw new Error(`No se encontró token en la respuesta`);
    }

    msg.token = token;
    node.log(`✅ Login OK - Token obtenido para ${msg.readerIp}`);

    const fechaDesde = flow.get('fechaDesde');
    const fechaHasta = flow.get('fechaHasta');

    const batchIndex = flow.get('batchIndex') || 0;
    const batchSize = 25;
    const start = batchIndex * batchSize;

    flow.set('batchSize', batchSize);

    const url = `http://${msg.readerIp}/goform/GetReportFormInfo` +
        `?_t=${Date.now()}` +
        `&userid=` +
        `&from=${fechaDesde}` +
        `&to=${fechaHasta}` +
        `&intime=00:00` +
        `&outtime=23:59` +
        `&start=${start}` +
        `&limit=${batchSize}`;

    msg.url = url;
    msg.method = 'GET';
    msg.headers = {
        'token': token,
        'Accept': 'application/json, text/plain, */*',
        'Referer': `http://${msg.readerIp}/index.html`,
        'Cache-Control': 'no-cache'
    };
    msg.payload = '';

    node.log(`📦 [${msg.readerIp}] Solicitando batch ${batchIndex + 1} (registros ${start} a ${start + batchSize - 1})`);

    const pausa = flow.get('pausaEntreConsultas') || 800;
    setTimeout(() => {
        node.send([msg, null]);
    }, pausa);

    return null;

} catch (e) {
    node.error(`❌ Error login para ${msg.readerIp}: ${e.message}`);
    marcarFalloYContinuar(e.message);
    return null;
}

function parseAnvizJSON(text) {
    if (typeof text !== 'string') return text;
    let cleaned = text.replace(/,(\s*})/g, '$1');
    cleaned = cleaned.replace(/,(\s*\])/g, '$1');
    cleaned = cleaned.replace(/([{,]\s*)([a-zA-Z_][a-zA-Z0-9_]*)\s*:/g, '$1"$2":');
    return JSON.parse(cleaned);
}

// Función para marcar reloj como fallido y pasar al siguiente
function marcarFalloYContinuar(errorMsg) {
    const readerIp = flow.get('readerIp');
    const faseReintento = flow.get('faseReintento') || false;
    const estadoRelojes = flow.get('estadoRelojes') || [];
    const estadoReloj = estadoRelojes.find(r => r.ip === readerIp);

    if (estadoReloj) {
        estadoReloj.estado = faseReintento ? 'FALLIDO_DEFINITIVO' : 'FALLIDO_PRIMERA';
        estadoReloj.error = errorMsg;
        estadoReloj.duracion = Math.round((Date.now() - flow.get('inicioRelojActual')) / 1000);
        flow.set('estadoRelojes', estadoRelojes);
    }

    if (!faseReintento) {
        const relojesParaReintento = flow.get('relojesParaReintento') || [];
        const relojActual = flow.get('relojActual');
        if (relojActual && !relojesParaReintento.find(r => r.ip === relojActual.ip)) {
            relojesParaReintento.push(relojActual);
            flow.set('relojesParaReintento', relojesParaReintento);
        }
    }

    const relojActualIndex = flow.get('relojActualIndex') || 0;
    flow.set('relojActualIndex', relojActualIndex + 1);

    setTimeout(() => {
        node.send([null, { payload: 'siguiente_reloj' }]);
    }, 2000);
}

try {
    let data = msg.payload;

    if (typeof data === 'string') {
        data = parseAnvizJSON(data);
    }

    if (data.code === 'error' || (data.retvalue !== 0 && data.retvalue !== undefined)) {
        throw new Error(`API error: ${data.msg || 'error'}`);
    }

    const records = data.record || [];
    const batchSize = flow.get('batchSize') || 25;
    const batchIndex = flow.get('batchIndex') || 0;

    if (!records || records.length === 0) {
        // Sin registros - marcar como completado y pasar al siguiente
        node.log(`ℹ [${msg.readerIp}] Sin registros en este batch - reloj completado`);
        flow.set('esUltimoBatch', true);
        flow.set('todosLosRegistros', []);
        flow.set('registroIndex', 0);

        return [msg, null];
    }

    // Guardar registros del batch actual
    flow.set('todosLosRegistros', records);
    flow.set('registroIndex', 0);

    node.log(`📦 [${msg.readerIp}] Batch ${batchIndex + 1}: ${records.length} registros obtenidos`);

    // Si obtuvimos menos que el batchSize, es el último batch
    if (records.length < batchSize) {
        flow.set('esUltimoBatch', true);
    } else {
        flow.set('esUltimoBatch', false);
    }

    return [msg, null];

} catch (e) {
    node.error(`❌ Error parseo batch para ${msg.readerIp}: ${e.message}`);
    marcarFalloYContinuar(e.message);
    return null;
}

const registros = flow.get('todosLosRegistros') || [];
const index = flow.get('registroIndex') || 0;
const readerIp = flow.get('readerIp');
const sucursal = flow.get('sucursal');

// SALIDAS:
// 1: registro a insertar
// 2: pasar al siguiente reloj (reloj completado)
// 3: solicitar siguiente batch

// Verificar si terminamos este batch
if (index >= registros.length) {
    const esUltimoBatch = flow.get('esUltimoBatch');

    if (esUltimoBatch) {
        // RELOJ COMPLETADO
        const totalProcesados = flow.get('totalProcesados') || 0;
        const totalInsertados = flow.get('totalInsertados') || 0;
        const duracion = Math.round((Date.now() - flow.get('inicioRelojActual')) / 1000);

        node.log('----------------------------------------');
        node.log(`✅ RELOJ ${readerIp} COMPLETADO`);
        node.log(`   📊 Procesados: ${totalProcesados} | Insertados: ${totalInsertados} | Duración: ${duracion}s`);
        node.log('----------------------------------------');

        // Actualizar estado del reloj
        const estadoRelojes = flow.get('estadoRelojes') || [];
        const estadoReloj = estadoRelojes.find(r => r.ip === readerIp);
        if (estadoReloj) {
            estadoReloj.estado = 'OK';
            estadoReloj.procesados = totalProcesados;
            estadoReloj.insertados = totalInsertados;
            estadoReloj.duracion = duracion;
            estadoReloj.error = null;
            flow.set('estadoRelojes', estadoRelojes);
        }

        // Actualizar estadísticas globales
        const estadisticas = flow.get('estadisticasGlobales');
        estadisticas.totalProcesados += totalProcesados;
        estadisticas.totalInsertados += totalInsertados;
        flow.set('estadisticasGlobales', estadisticas);

        // Pasar al siguiente reloj
        flow.set('relojActualIndex', (flow.get('relojActualIndex') || 0) + 1);

        const pausaEntreRelojes = flow.get('pausaEntreRelojes') || 2000;
        setTimeout(() => {
            node.send([null, { payload: 'siguiente_reloj' }, null]);
        }, pausaEntreRelojes);

        return null;
    } else {
        // SIGUIENTE BATCH
        const batchIndex = flow.get('batchIndex') || 0;
        flow.set('batchIndex', batchIndex + 1);
        flow.set('registroIndex', 0);

        node.log(`🔄 [${readerIp}] Batch ${batchIndex + 1} completado. Solicitando siguiente...`);

        const pausa = flow.get('pausaEntreConsultas') || 800;
        setTimeout(() => {
            node.send([null, null, { payload: 'next_batch' }]);
        }, pausa);

        return null;
    }
}

// Procesar registro actual
const record = registros[index];
const dniRaw = record.id || '';
const dni = String(dniRaw).padStart(5, '0');
const fecha = record.date || '';
const firstin = record.firstin || '';
const lastout = record.lastout || '';
const batchIndex = flow.get('batchIndex') || 0;
const totalEnBatch = registros.length;

if (!dni || !fecha) {
    node.log(`⚠ [${readerIp}] [B${batchIndex + 1}] [${index+1}/${totalEnBatch}] Sin DNI/Fecha - SKIP`);
    flow.set('registroIndex', index + 1);

    setTimeout(() => {
        node.send([{ payload: 'next' }, null, null]);
    }, 50);

    return null;
}

// Generar filas: firstin y/o lastout
const sqlRows = [];

if (firstin && firstin !== '') {
    sqlRows.push({
        Dni: dni,
        Fecha: fecha,
        Hora: firstin,
        Sucursal: sucursal,
        ipreloj: readerIp
    });
}

if (lastout && lastout !== '') {
    sqlRows.push({
        Dni: dni,
        Fecha: fecha,
        Hora: lastout,
        Sucursal: sucursal,
        ipreloj: readerIp
    });
}

if (sqlRows.length === 0) {
    node.log(`⚠ [${readerIp}] [B${batchIndex + 1}] [${index+1}/${totalEnBatch}] Sin horas - SKIP`);
    flow.set('registroIndex', index + 1);

    setTimeout(() => {
        node.send([{ payload: 'next' }, null, null]);
    }, 50);

    return null;
}

msg.sqlRows = sqlRows;
msg.registroActual = index + 1;
msg.totalRegistros = totalEnBatch;
msg.batchActual = batchIndex + 1;

flow.set('totalProcesados', (flow.get('totalProcesados') || 0) + 1);

node.log(`📝 [${readerIp}] [B${batchIndex + 1}] [${index+1}/${totalEnBatch}] DNI: ${dni} - ${sqlRows.length} fichada(s)`);

return [msg, null, null];

const rows = msg.sqlRows;

if (!rows || rows.length === 0) return null;

function escapeSql(value) {
    if (value === null || value === undefined) return '';
    return String(value).replace(/'/g, "''");
}

// MERGE para respetar el índice único UX_RelojImportacion_Dedup
// Índice compuesto por: EmpleadoId, Sucursal, Dni, Fecha, HoraSeg (columna calculada)
let sql = '';

rows.forEach(row => {
    sql += `
MERGE INTO RelojImportacion AS target
USING (
    SELECT 
        '${escapeSql(row.Dni)}' AS Dni,
        '${escapeSql(row.Fecha)}' AS Fecha,
        '${escapeSql(row.Hora)}' AS Hora,
        '${escapeSql(row.Sucursal)}' AS Sucursal,
        '${escapeSql(row.ipreloj)}' AS ipreloj,
        (
            SELECT TOP 1 EmpleadoID 
            FROM RelojImportacion WITH (NOLOCK)
            WHERE Dni = '${escapeSql(row.Dni)}' 
            AND EmpleadoID IS NOT NULL
        ) AS EmpleadoID
) AS source
ON (
    (target.EmpleadoId IS NULL AND source.EmpleadoID IS NULL) 
    OR (target.EmpleadoId = source.EmpleadoID)
)
AND target.Sucursal = source.Sucursal
AND target.Dni = source.Dni 
AND target.Fecha = source.Fecha 
AND target.HoraSeg = source.Hora
WHEN NOT MATCHED THEN
    INSERT (Id, Dni, Fecha, Hora, Sucursal, ipreloj, EmpleadoID)
    VALUES (NEWID(), source.Dni, source.Fecha, source.Hora, source.Sucursal, source.ipreloj, source.EmpleadoID);
`;
});

msg.payload = sql;
msg.topic = sql;
msg.query = sql;

return msg;

// Contar filas afectadas
let rowsAffected = 0;

if (msg.payload && msg.payload.rowsAffected) {
    if (Array.isArray(msg.payload.rowsAffected)) {
        rowsAffected = msg.payload.rowsAffected.reduce((a, b) => a + b, 0);
    } else {
        rowsAffected = msg.payload.rowsAffected;
    }
}

if (rowsAffected > 0) {
    flow.set('totalInsertados', (flow.get('totalInsertados') || 0) + rowsAffected);
    node.log(`   ✅ ${rowsAffected} fichada(s) insertada(s)`);
} else {
    node.log(`   ⏭ Fichada(s) ya existente(s) - SKIP`);
}

// Incrementar índice
const index = flow.get('registroIndex') || 0;
flow.set('registroIndex', index + 1);

// Delay para no saturar la BD
setTimeout(() => {
    node.send({ payload: 'next' });
}, 150);

return null;

// Redirigir a login para nuevo token y batch
const readerIp = flow.get('readerIp');
const pausa = flow.get('pausaEntreConsultas') || 800;

node.log(`🔄 Solicitando siguiente batch para ${readerIp}...`);

setTimeout(() => {
    node.send({
        payload: 'next_batch',
        readerIp: readerIp,
        sucursal: flow.get('sucursal')
    });
}, pausa);

return null;

const estadoRelojes = flow.get('estadoRelojes') || [];
const estadisticas = flow.get('estadisticasGlobales') || {};
const duracion = ((Date.now() - estadisticas.inicioProceso) / 1000).toFixed(2);

// Contar estados
const stats = {
    OK: 0,
    FALLIDO_PRIMERA: 0,
    FALLIDO_DEFINITIVO: 0,
    PENDIENTE: 0,
    PROCESANDO: 0
};

estadoRelojes.forEach(r => {
    stats[r.estado] = (stats[r.estado] || 0) + 1;
});

node.log('');
node.log('╔════════════════════════════════════════════════════════════════╗');
node.log('║          🏁 RESUMEN FINAL DEL PROCESO ANVIZ                    ║');
node.log('╚════════════════════════════════════════════════════════════════╝');
node.log(`⏱  Duración total: ${duracion} segundos (${(duracion/60).toFixed(2)} min)`);
node.log(`📊 Total registros procesados: ${estadisticas.totalProcesados}`);
node.log(`📊 Total fichadas insertadas: ${estadisticas.totalInsertados}`);
node.log('');
node.log('┌─────────────────────────────────────────────────────────────────┐');
node.log('│ ESTADO POR RELOJ:                                               │');
node.log('├─────────────────────────────────────────────────────────────────┤');

estadoRelojes.forEach(r => {
    let icono = '❓';
    if (r.estado === 'OK') icono = '✅';
    else if (r.estado === 'FALLIDO_DEFINITIVO') icono = '❌';
    else if (r.estado === 'FALLIDO_PRIMERA') icono = '⚠';

    const linea = `│ ${icono} ${r.ip} | ${r.estado.padEnd(20)} | Proc: ${String(r.procesados).padStart(4)} | Ins: ${String(r.insertados).padStart(4)} | ${r.duracion}s | Intentos: ${r.intentos}`;
    node.log(linea);

    if (r.error) {
        node.log(`│    └─ Error: ${r.error}`);
    }
});

node.log('├─────────────────────────────────────────────────────────────────┤');
node.log(`│ ✅ Exitosos: ${stats.OK} | ❌ Fallidos: ${stats.FALLIDO_DEFINITIVO} | ⚠ Recuperados: ${stats.FALLIDO_PRIMERA}`);
node.log('└─────────────────────────────────────────────────────────────────┘');

// Liberar el bloqueo global
global.set('anvizProcesoGlobalActivo', false);
global.set('anvizInicioProceso', 0);

node.status({ 
    fill: stats.FALLIDO_DEFINITIVO > 0 ? 'red' : 'green', 
    shape: 'dot', 
    text: `OK: ${stats.OK} | Fallos: ${stats.FALLIDO_DEFINITIVO}` 
});

// Construir mensaje de resumen para el debug
msg.payload = {
    duracionSegundos: parseFloat(duracion),
    duracionMinutos: parseFloat((duracion/60).toFixed(2)),
    totalProcesados: estadisticas.totalProcesados,
    totalInsertados: estadisticas.totalInsertados,
    relojes: estadoRelojes,
    resumen: {
        exitosos: stats.OK,
        fallidos: stats.FALLIDO_DEFINITIVO,
        recuperadosEnReintento: stats.FALLIDO_PRIMERA - stats.FALLIDO_DEFINITIVO
    },
    timestamp: new Date().toISOString()
};

return msg;

const rows = msg.sqlRows;

if (!rows || rows.length === 0) return null;

function escapeSql(value) {
    if (value === null || value === undefined) return '';
    return String(value).replace(/'/g, "''");
}

// INSERT con verificación NOT EXISTS para evitar duplicados
let sql = '';

rows.forEach(row => {
    sql += `
INSERT INTO RelojImportacion (Id, Dni, Fecha, Hora, Sucursal, ipreloj)
SELECT 
    NEWID(),
    '${escapeSql(row.Dni)}',
    '${escapeSql(row.Fecha)}',
    '${escapeSql(row.Hora)}',
    '${escapeSql(row.Sucursal)}',
    '${escapeSql(row.ipreloj)}'
WHERE NOT EXISTS (
    SELECT 1 FROM RelojImportacion WITH (NOLOCK)
    WHERE Dni = '${escapeSql(row.Dni)}' 
    AND Fecha = '${escapeSql(row.Fecha)}' 
    AND Hora = '${escapeSql(row.Hora)}' 
    AND Sucursal = '${escapeSql(row.Sucursal)}' 
    AND ipreloj = '${escapeSql(row.ipreloj)}'
);
`;
});

msg.payload = sql;
msg.topic = sql;
msg.query = sql;

return msg;

// Forzar reset del bloqueo global
global.set('anvizProcesoGlobalActivo', false);
global.set('anvizInicioProceso', 0);

node.warn('🔓 BLOQUEO FORZADO A RESET - Proceso liberado');
node.status({ fill: 'green', shape: 'dot', text: 'Desbloqueado' });

msg.payload = 'Bloqueo liberado correctamente';
return msg;
